                        *cp = policies[c.Rand.Intn(len(policies))]
                },
                func(p *batch.PodFailurePolicyOnPodConditionsPattern, c fuzz.Continue) {
                        c.FuzzNoCustom(p)
                        if p.Status == "" {
                                p.Status = api.ConditionTrue
                        }
                },
        }
